    js_code = page.evaluate('''() => {
        const result = {};

        // 获取所有script标签的内容
        const scripts = [];
        document.querySelectorAll('script').forEach(s => {
            if (s.textContent && s.textContent.length > 100) {
                scripts.push(s.textContent.substring(0, 2000));
            }
        });
        result.scripts = scripts.slice(0, 5);

        // 检查全局变量
        result.globals = {};
        for (const key of Object.keys(window)) {
            if (key.includes('Stream') || key.includes('stream') || 
                key.includes('Channel') || key.includes('WebVideo')) {
                result.globals[key] = typeof window[key];
            }
        }

        // 检查WebVideoCtrl对象的方法
        if (typeof WebVideoCtrl !== 'undefined') {
