#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""研究海康官方web管理端的码流切换实现 - 拦截WebSocket连接"""

from playwright.sync_api import sync_playwright
import time

ws_connections = []

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    context = browser.new_context(viewport={'width': 1920, 'height': 1080})

    # 拦截WebSocket连接
    context.on('websocket', lambda ws: ws_connections.append({
        'url': ws.url,
        'opened': time.strftime('%H:%M:%S'),
    }))

    page = context.new_page()

    # 打开海康web管理端
    print('1. 打开海康web管理端...')
    page.goto('http://192.168.5.72', timeout=30000)
    time.sleep(3)

    # 截取登录页面HTML
    login_html = page.content()

    # 查找登录表单
    print('2. 分析登录页面...')
    inputs = page.query_selector_all('input')
    for inp in inputs:
        name = inp.get_attribute('name') or ''
        type_ = inp.get_attribute('type') or ''
        id_ = inp.get_attribute('id') or ''
        print(f'  input: name={name}, type={type_}, id={id_}')

    buttons = page.query_selector_all('button')
    for btn in buttons:
        text = btn.text_content() or ''
        id_ = btn.get_attribute('id') or ''
        print(f'  button: text={text}, id={id_}')

    # 登录
    print('3. 登录...')
    try:
        username_input = page.query_selector('input[name="userName"]') or page.query_selector('input[name="username"]') or page.query_selector('input[type="text"]')
        password_input = page.query_selector('input[name="password"]') or page.query_selector('input[type="password"]')
        if username_input:
            username_input.fill('admin')
        if password_input:
            password_input.fill('Nftw1357')

        # 点击登录
        login_btn = page.query_selector('input[type="submit"]') or page.query_selector('button.login-btn') or page.query_selector('.btn-login')
        if login_btn:
            login_btn.click()
        else:
            page.keyboard.press('Enter')
    except Exception as e:
        print(f'  登录异常: {e}')

    time.sleep(5)
    page.screenshot(path='test_results/hik_after_login2.png')

    print(f'  当前URL: {page.url}')
    print(f'  WebSocket连接数: {len(ws_connections)}')
    for ws in ws_connections:
        print(f'  WebSocket: {ws["url"][:100]}')

    # 查找预览按钮
    print('4. 进入预览...')
    try:
        # 尝试多种方式找到预览入口
        preview_btn = page.query_selector('text=预览') or page.query_selector('text=Live Preview') or page.query_selector('[data-page="preview"]')
        if preview_btn:
            preview_btn.click()
            time.sleep(3)
    except Exception as e:
        print(f'  预览异常: {e}')

    page.screenshot(path='test_results/hik_preview2.png')
    print(f'  WebSocket连接数: {len(ws_connections)}')
    for ws in ws_connections:
        print(f'  WebSocket: {ws["url"][:100]}')

    # 分析JavaScript中的码流切换实现
    print('5. 分析码流切换JavaScript...')
    stream_analysis = page.evaluate('''() => {
        const result = {};

        // 检查所有全局函数
        for (const key of Object.keys(window)) {
            try {
                if (typeof window[key] === 'function' && (key.includes('Stream') || key.includes('stream') || key.includes('change'))) {
                    result[key] = window[key].toString().substring(0, 300);
                }
            } catch(e) {}
        }

        // 检查所有select元素（码流选择）
        document.querySelectorAll('select').forEach(sel => {
            const opts = [];
            sel.querySelectorAll('option').forEach(opt => opts.push(opt.value + ':' + opt.textContent));
            if (opts.some(o => o.includes('码流') || o.includes('stream') || o.includes('主') || o.includes('子'))) {
                result['select_' + sel.id] = opts.join('|');
            }
        });

        // 检查WebVideoCtrl
        if (typeof WebVideoCtrl !== 'undefined') {
            const methods = Object.getOwnPropertyNames(WebVideoCtrl.prototype || WebVideoCtrl);
            result['WebVideoCtrl_methods'] = methods.filter(m => m.startsWith('I_') || m.toLowerCase().includes('stream')).join(',');
        }

        return result;
    }''')

    for key, value in stream_analysis.items():
        print(f'  {key}: {value}')

    browser.close()
    print('\n分析完成！')

