#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""研究海康官方web管理端 - 获取HTML和JS内容"""

from playwright.sync_api import sync_playwright
import time
import re

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    page = browser.new_page(viewport={'width': 1920, 'height': 1080})

    # 打开海康web管理端
    print('1. 打开海康web管理端...')
    page.goto('http://192.168.5.72/doc/index.html', timeout=30000, wait_until='networkidle')
    time.sleep(5)

    # 获取页面HTML
    html_content = page.content()
    print(f'  页面HTML长度: {len(html_content)}')

    # 查找所有script标签的src属性
    print('2. 查找JavaScript文件...')
    script_srcs = page.evaluate('''() => {
        const srcs = [];
        document.querySelectorAll('script[src]').forEach(s => {
            srcs.push(s.src);
        });
        return srcs;
    }''')

    for src in script_srcs:
        print(f'  Script: {src}')

    # 获取页面中inline JavaScript内容
    print('3. 分析inline JavaScript...')
    inline_scripts = page.evaluate('''() => {
        const scripts = [];
        document.querySelectorAll('script:not([src])').forEach(s => {
            if (s.textContent && s.textContent.length > 50) {
                scripts.push(s.textContent);
            }
        });
        return scripts;
    }''')

    # 查找码流切换相关的代码
    print('4. 搜索码流切换关键词...')
    all_content = html_content + '\n'.join(inline_scripts)

    # 搜索关键词
    keywords = ['iStreamType', 'StreamType', 'streamType', '码流', '主码流', '子码流', 'changeStream', 'switchStream', 'I_StartRealPlay', 'I_Stop']
    for kw in keywords:
        matches = re.findall(kw + '.{0,100}', all_content)
        if matches:
            print(f'  找到 {kw}: {len(matches)} 次')
            for m in matches[:3]:
                print(f'    {m[:80]}')

    # 检查是否有iframe
    print('5. 检查iframe...')
    frames = page.frames
    print(f'  iframe数量: {len(frames)}')
    for i, frame in enumerate(frames):
        print(f'  iframe {i}: {frame.url}')

    # 保存分析结果
    with open('test_results/hik_analysis.html', 'w', encoding='utf-8') as f:
        f.write('=== 海康web管理端HTML ===\n\n')
        f.write(html_content)

    with open('test_results/hik_inline_js.js', 'w', 'encoding='utf-8') as f:
        f.write('// 海康web管理端inline JavaScript\n\n')
        for s in inline_scripts:
            f.write(s + '\n\n---\n\n')

    print('\n分析结果已保存到 test_results/hik_analysis.html 和 test_results/hik_inline_js.js')

    browser.close()

