function startFirstFrameDetection() {
    var detectionAttempts = 0;
    var maxAttempts = 30; // 30次检测，每次500ms，共15秒

    var detectFrame = function() {
        detectionAttempts++;
        var canvas = document.getElementById('divPlugin_playCanvas0');
        if (canvas && canvas.width > 0 && canvas.height > 0) {
            try {
                var ctx = canvas.getContext('2d');
                var imageData = ctx.getImageData(0, 0, Math.min(canvas.width, 10), Math.min(canvas.height, 10));
                // 检查是否有非零像素
                var hasData = false;
                for (var i = 0; i < imageData.data.length; i += 4) {
                    if (imageData.data[i] > 0 || imageData.data[i+1] > 0 || imageData.data[i+2] > 0) {
                        hasData = true;
                        break;
                    }
                }
                if (hasData) {
                    console.log('[WASM SDK] 首帧检测成功!');
                    g_bPlaying2 = true;
                    if (typeof ptzLog === 'function') ptzLog('视频播放中', 'success');
                    if (window.updateWasmStatus) window.updateWasmStatus('playing');
                    if (window.startPtzPositionPoll) window.startPtzPositionPoll();
                    return;
                }
            } catch(e) {}
        }
        if (detectionAttempts < maxAttempts) {
            setTimeout(detectFrame, 500);
        } else {
            console.log('[WASM SDK] 首帧检测超时');
            if (typeof ptzLog === 'function') ptzLog('视频连接超时', 'warning');
            if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
        }
    };    setTimeout(detectFrame, 1000);
}
window.startFirstFrameDetection = startFirstFrameDetection;

